# Load packageinfo data
# var_function-call-4730495071124553966 contains the list of records
data_str = locals()['var_function-call-4730495071124553966']
if isinstance(data_str, str):
    packages_data = json.loads(data_str)
else:
    packages_data = data_str

# Find latest version for each package
latest_versions = {}
for p in packages_data:
    name = p['Name']
    ver = p['Version']
    ts = float(p['UpstreamPublishedAt'])

    if name not in latest_versions:
        latest_versions[name] = {'Version': ver, 'Timestamp': ts}
    else:
        if ts > latest_versions[name]['Timestamp']:
            latest_versions[name] = {'Version': ver, 'Timestamp': ts}

# The ordered top 5 packages
top_5_order = [
    '@docly/web',
    '@dylanvann/svelte',
    '@dumc11/tailwindcss',
    '@edgarai/strapi-provider-upload-local',
    '@dman777/shadow-dom-quill-temp'
]

# Construct result
result_list = []
for name in top_5_order:
    ver = latest_versions.get(name, {}).get('Version', 'Unknown')
    result_list.append(f"{name} (Version: {ver})")

print("__RESULT__:")
print(json.dumps(result_list))
"}

